def tables(self):
    db_table_names = OrderedSet([t._tablename for t in self.db])
    meta_table_names = OrderedSet(list(self.meta.tables))

    #: new tables
    self.ops.extend(
        [
            CreateTableOp.from_table(self._build_metatable(self.db[table_name])) 
            for table_name in db_table_names.difference(meta_table_names)
        ]
    )
    [
        self.indexes_and_uniques(self.db[table_name], self._build_metatable(self.db[table_name]))
        or self.foreign_keys(self.db[table_name], self._build_metatable(self.db[table_name]))
        for table_name in db_table_names.difference(meta_table_names)
    ]

    #: removed tables
    removal_ops = [
        [self.ops.append(DropIndexOp.from_index(idx)) for idx in metatable.indexes.values()]
        for table_name, metatable in [(t, self.meta.tables[t]) for t in meta_table_names.difference(db_table_names)]
    ]
    self.ops.extend(
        [
            DropTableOp.from_table(self.meta.tables[table_name]) 
            for table_name in meta_table_names.difference(db_table_names)
        ]
    )

    #: existing tables
    [
        self.columns(self.db[table_name], self.meta.tables[table_name]) or
        self.table(self.db[table_name], self.meta.tables[table_name])
        for table_name in meta_table_names.intersection(db_table_names)
    ]

