def __init__(self, root: str, lang: str, split: str) -> None:
        assert split in self.SPLITS and lang in self.LANGPAIRS
        _root = Path(root) / f"{lang}" / "data" / split
        wav_root, txt_root = _root / "wav", _root / "txt"
        assert _root.is_dir() and wav_root.is_dir() and txt_root.is_dir()
        # Load audio segments
        try:
            import yaml
        except ImportError:
            print(
                "Please install PyYAML to load the Multilingual TEDx YAML files"
            )
        with open(txt_root / f"{split}.yaml") as f:
            segments = yaml.load(f, Loader=yaml.BaseLoader)
        # Load source and target utterances
        src, tgt = lang.split("-")
        for _lang in [src, tgt]:
            with open(txt_root / f"{split}.{_lang}") as f:
                utterances = [r.strip() for r in f]
            assert len(segments) == len(utterances)
            segments = [
                {**segment, _lang: utterance}
                for segment, utterance in zip(segments, utterances)
            ]
        # Gather info
        self.data = [
            (
                (wav_path := wav_root / wav_filename.replace(".wav", ".flac")).as_posix(),
                offset := int(float(segment["offset"]) * sample_rate),  # noqa: F841
                n_frames := int(float(segment["duration"]) * sample_rate),  # noqa: F841
                sample_rate := sf.info(wav_path.as_posix()).samplerate,  # noqa: F841
                segment[src],
                segment[tgt],
                segment["speaker_id"],
                tgt,
                f"{wav_path.stem}_{i}",
            )
            for wav_filename, _seg_group in groupby(segments, lambda x: x["wav"])
            for i, segment in enumerate(sorted(_seg_group, key=lambda x: float(x["offset"])))
        ]

