import os

def program_paths(program_name):
    exts = filter(None, os.environ.get('PATHEXT', '').split(os.pathsep))
    return [
        pext
        for p in os.environ['PATH'].split(os.pathsep)
        for e in [''] + list(exts)
        if os.access(pext := os.path.join(p, program_name) + e, os.X_OK)
    ]

