def translate_style(name, style):
    parts = ['#%s' % name]
    if style.pseudo_element:
        root = parts.pop()
        parts = [root + '::%s' % pe.strip() for pe in style.pseudo_element.split(',')]
    if style.pseudo_class:
        these = parts[:]
        parts = [this + ':%s' % pc.strip() for pc in style.pseudo_class.split(',') for this in these]
    selector = ','.join(parts)
    body = '{\n%s\n}' % _translate_style_body(style)
    return '%s %s' % (selector, body)

