def _validate_non_empty_object(self) -> List[str]:
    """
    Validates that object types implement at least one field.
    :return: a list of errors
    :rtype: List[str]
    """
    return [
        f"Type < {type_name} > has no fields."
        for type_name, gql_type in self.type_definitions.items()
        if isinstance(gql_type, GraphQLObjectType) and not any(
            not field_name.startswith("__")
            for field_name in gql_type.implemented_fields
        )
    ]

